  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { bindActionCreators } from 'redux';
  4	import { KialiDispatch } from 'types/Redux';
  5	import { Card, CardBody, Checkbox, Toolbar, ToolbarGroup, ToolbarItem } from '@patternfly/react-core';
  6	import { kialiStyle } from 'styles/StyleUtils';
  7	import * as API from 'services/Api';
  8	import { KialiAppState } from 'store/Store';
  9	import { TimeRange, evalTimeRange, TimeInMilliseconds, isEqualTimeRange, IntervalInMilliseconds } from 'types/Common';
 10	import { Direction, IstioMetricsOptions, Reporter } from 'types/MetricsOptions';
 11	import * as AlertUtils from 'utils/AlertUtils';
 12	import { RenderComponentScroll } from 'components/Nav/Page';
 13	import * as MetricsHelper from './Helper';
 14	import { KioskElement } from '../Kiosk/KioskElement';
 15	import { MetricsSettings, LabelsSettings } from '../MetricsOptions/MetricsSettings';
 16	import { MetricsSettingsDropdown } from '../MetricsOptions/MetricsSettingsDropdown';
 17	import { MetricsReporter } from '../MetricsOptions/MetricsReporter';
 18	import { TimeDurationModal } from '../Time/TimeDurationModal';
 19	import { location, router, URLParam } from 'app/History';
 20	import { MetricsObjectTypes } from 'types/Metrics';
 21	import { GrafanaInfo } from 'types/GrafanaInfo';
 22	import { MessageType } from 'types/MessageCenter';
 23	import { SpanOverlay, JaegerLineInfo } from './SpanOverlay';
 24	import { ChartModel, DashboardModel } from 'types/Dashboards';
 25	import { Overlay } from 'types/Overlay';
 26	import { RawOrBucket } from 'types/VictoryChartInfo';
 27	import { Dashboard } from 'components/Charts/Dashboard';
 28	import { refreshIntervalSelector, timeRangeSelector } from 'store/Selectors';
 29	import { UserSettingsActions } from 'actions/UserSettingsActions';
 30	import { KialiCrippledFeatures } from 'types/ServerConfig';
 31	import { TimeDurationIndicator } from '../Time/TimeDurationIndicator';
 32	import { ApiResponse } from 'types/Api';
 33	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 34	import { TraceSpansLimit } from './TraceSpansLimit';
 35	import { GrafanaLinks } from './GrafanaLinks';
 36	import { PersesInfo } from '../../types/PersesInfo';
 37	import { PersesLinks } from './PersesLinks';
 38	import { ExternalServiceInfo } from '../../types/StatusState';
 39	
 40	type MetricsState = {
 41	  crippledFeatures?: KialiCrippledFeatures;
 42	  dashboard?: DashboardModel;
 43	  grafanaInfo: GrafanaInfo;
 44	  isTimeOptionsOpen: boolean;
 45	  labelsSettings: LabelsSettings;
 46	  persesInfo: PersesInfo;
 47	  showSpans: boolean;
 48	  showTrendlines: boolean;
 49	  spanOverlay?: Overlay<JaegerLineInfo>;
 50	  tabHeight: number;
 51	  traceLimit: number;
 52	};
 53	
 54	type ObjectId = {
 55	  cluster?: string;
 56	  namespace: string;
 57	  object: string;
 58	};
 59	
 60	type IstioMetricsProps = ObjectId & {
 61	  direction: Direction;
 62	  includeAmbient: boolean;
 63	  objectType: MetricsObjectTypes;
 64	} & {
 65	  lastRefreshAt: TimeInMilliseconds;
 66	};
 67	
 68	type ReduxStateProps = {
 69	  externalServices: ExternalServiceInfo[];
 70	  kiosk: string;
 71	  refreshInterval: IntervalInMilliseconds;
 72	  timeRange: TimeRange;
 73	  tracingIntegration: boolean;
 74	};
 75	
 76	type ReduxDispatchProps = {
 77	  setTimeRange: (range: TimeRange) => void;
 78	};
 79	
 80	type Props = ReduxStateProps & ReduxDispatchProps & IstioMetricsProps;
 81	
 82	// lower that the standard default, we apply it to several small charts
 83	const traceLimitDefault = 20;
 84	
 85	const fullHeightStyle = kialiStyle({
 86	  height: '100%'
 87	});
 88	
 89	class IstioMetricsComponent extends React.Component<Props, MetricsState> {
 90	  toolbarRef: React.RefObject<HTMLDivElement>;
 91	  options: IstioMetricsOptions;
 92	  spanOverlay: SpanOverlay;
 93	  static grafanaInfoPromise: Promise<GrafanaInfo | undefined> | undefined;
 94	  static persesInfoPromise: Promise<PersesInfo | undefined> | undefined;
 95	
 96	  constructor(props: Props) {
 97	    super(props);
 98	    this.toolbarRef = React.createRef<HTMLDivElement>();
 99	    const settings = MetricsHelper.retrieveMetricsSettings(traceLimitDefault);
100	    this.options = this.initOptions(settings);
101	
102	    // Initialize active filters from URL
103	    this.state = {
104	      labelsSettings: settings.labelsSettings,
105	      grafanaInfo: {
106	        externalLinks: []
107	      },
108	      isTimeOptionsOpen: false,
109	      persesInfo: {
110	        externalLinks: []
111	      },
112	      tabHeight: 300,
113	      showSpans: settings.showSpans,
114	      showTrendlines: settings.showTrendlines,
115	      traceLimit: settings.spanLimit
116	    };
117	
118	    this.spanOverlay = new SpanOverlay(changed => {
119	      this.setState({ spanOverlay: changed });
120	    });
121	  }
122	
123	  private initOptions(settings: MetricsSettings): IstioMetricsOptions {
124	    const options: IstioMetricsOptions = {
125	      direction: this.props.direction,
126	      includeAmbient: this.props.includeAmbient,
127	      reporter: MetricsReporter.initialReporter(this.props.direction)
128	    };
129	
130	    const defaultLabels = [
131	      this.props.direction === 'inbound' ? 'source_canonical_service' : 'destination_canonical_service',
132	      this.props.direction === 'inbound' ? 'source_workload_namespace' : 'destination_workload_namespace'
133	    ];
134	
135	    MetricsHelper.settingsToOptions(settings, options, defaultLabels);
136	
137	    return options;
138	  }
139	
140	  componentDidMount(): void {
141	    API.getCrippledFeatures().then(response => {
142	      this.setState({ crippledFeatures: response.data });
143	    });
144	
145	    this.fetchGrafanaInfo();
146	    this.fetchPersesInfo();
147	    this.refresh();
148	  }
149	
150	  componentDidUpdate(prevProps: Props, prevState: MetricsState): void {
151	    if (
152	      this.props.direction !== prevProps.direction ||
153	      this.props.namespace !== prevProps.namespace ||
154	      this.props.object !== prevProps.object ||
155	      this.props.objectType !== prevProps.objectType ||
156	      this.props.lastRefreshAt !== prevProps.lastRefreshAt ||
157	      this.state.showSpans !== prevState.showSpans ||
158	      this.state.traceLimit !== prevState.traceLimit ||
159	      !isEqualTimeRange(this.props.timeRange, prevProps.timeRange)
160	    ) {
161	      if (this.props.direction !== prevProps.direction) {
162	        const settings = MetricsHelper.retrieveMetricsSettings(this.state.traceLimit);
163	        this.options = this.initOptions(settings);
164	
165	        this.setState({
166	          labelsSettings: settings.labelsSettings,
167	          showSpans: settings.showSpans,
168	          showTrendlines: settings.showTrendlines,
169	          traceLimit: settings.spanLimit
170	        });
171	      }
172	
173	      this.spanOverlay.reset();
174	      this.refresh();
175	    }
176	  }
177	
178	  private refresh = (): void => {
179	    this.fetchMetrics();
180	
181	    if (this.state.showSpans) {
182	      this.spanOverlay.fetch({
183	        cluster: this.props.cluster,
184	        limit: this.state.traceLimit,
185	        namespace: this.props.namespace,
186	        range: this.props.timeRange,
187	        target: this.props.object,
188	        targetKind: this.props.objectType
189	      });
190	    }
191	  };
192	
193	  private fetchMetrics = (): Promise<void> => {
194	    // Time range needs to be reevaluated everytime fetching
195	    MetricsHelper.timeRangeToOptions(this.props.timeRange, this.options);
196	    let opts = { ...this.options };
197	
198	    if (opts.reporter === 'both') {
199	      opts.byLabels = (opts.byLabels ?? []).concat('reporter');
200	    }
201	
202	    let promise: Promise<ApiResponse<DashboardModel>>;
203	
204	    switch (this.props.objectType) {
205	      case MetricsObjectTypes.WORKLOAD:
206	        promise = API.getWorkloadDashboard(this.props.namespace, this.props.object, opts, this.props.cluster);
207	        break;
208	      case MetricsObjectTypes.APP:
209	        promise = API.getAppDashboard(this.props.namespace, this.props.object, opts, this.props.cluster);
210	        break;
211	      case MetricsObjectTypes.SERVICE:
212	      default:
213	        promise = API.getServiceDashboard(this.props.namespace, this.props.object, opts, this.props.cluster);
214	        break;
215	    }
216	
217	    return promise
218	      .then(response => {
219	        const labelsSettings = MetricsHelper.extractLabelsSettings(response.data, this.state.labelsSettings);
220	
221	        this.setState({
222	          dashboard: response.data,
223	          labelsSettings: labelsSettings
224	        });
225	      })
226	      .catch(error => {
227	        AlertUtils.addError('Could not fetch metrics.', error);
228	        throw error;
229	      });
230	  };
231	
232	  private fetchGrafanaInfo(): void {
233	    if (this.props.externalServices.find(service => service.name.toLowerCase() === 'grafana')) {
234	      if (!IstioMetricsComponent.grafanaInfoPromise) {
235	        IstioMetricsComponent.grafanaInfoPromise = API.getGrafanaInfo().then(response => {
236	          if (response.status === 204) {
237	            return undefined;
238	          }
239	
240	          return response.data;
241	        });
242	      }
243	
244	      IstioMetricsComponent.grafanaInfoPromise
245	        .then(grafanaInfo => {
246	          if (grafanaInfo) {
247	            this.setState({ grafanaInfo: grafanaInfo });
248	          } else {
249	            this.setState({ grafanaInfo: { externalLinks: [] } });
250	          }
251	        })
252	        .catch(err => {
253	          AlertUtils.addMessage({
254	            ...AlertUtils.extractApiError('Could not fetch Grafana info. Turning off links to Grafana.', err),
255	            group: 'default',
256	            type: MessageType.INFO,
257	            showNotification: false
258	          });
259	        });
260	    }
261	  }
262	
263	  private fetchPersesInfo(): void {
264	    if (this.props.externalServices.find(service => service.name.toLowerCase() === 'perses')) {
265	      if (!IstioMetricsComponent.persesInfoPromise) {
266	        IstioMetricsComponent.persesInfoPromise = API.getPersesInfo().then(response => {
267	          if (response.status === 204) {
268	            return undefined;
269	          }
270	
271	          return response.data;
272	        });
273	      }
274	
275	      IstioMetricsComponent.persesInfoPromise
276	        .then(persesInfo => {
277	          if (persesInfo) {
278	            this.setState({ persesInfo: persesInfo });
279	          } else {
280	            this.setState({ persesInfo: { externalLinks: [] } });
281	          }
282	        })
283	        .catch(err => {
284	          AlertUtils.addMessage({
285	            ...AlertUtils.extractApiError('Could not fetch Perses info. Turning off links to Perses.', err),
286	            group: 'default',
287	            type: MessageType.INFO,
288	            showNotification: false
289	          });
290	        });
291	    }
292	  }
293	
294	  private onMetricsSettingsChanged = (settings: MetricsSettings): void => {
295	    const defaultLabels = [
296	      this.props.direction === 'inbound' ? 'source_canonical_service' : 'destination_canonical_service'
297	    ];
298	
299	    MetricsHelper.settingsToOptions(settings, this.options, defaultLabels);
300	    this.fetchMetrics();
301	  };
302	
303	  private onLabelsFiltersChanged = (labelsFilters: LabelsSettings): void => {
304	    this.setState({ labelsSettings: labelsFilters });
305	  };
306	
307	  private onReporterChanged = (reporter: Reporter): void => {
308	    this.options.reporter = reporter;
309	    this.fetchMetrics();
310	  };
311	
312	  private onClickDataPoint = (_chart: ChartModel, datum: RawOrBucket<JaegerLineInfo>): void => {
313	    if ('start' in datum && 'end' in datum) {
314	      // Zoom-in bucket
315	      this.onDomainChange([datum.start as Date, datum.end as Date]);
316	    } else if ('traceId' in datum) {
317	      const traceId = datum.traceId;
318	      const spanId = datum.spanId;
319	
320	      const domain =
321	        this.props.objectType === MetricsObjectTypes.APP
322	          ? 'applications'
323	          : this.props.objectType === MetricsObjectTypes.SERVICE
324	          ? 'services'
325	          : 'workloads';
326	
327	      const traceUrl = `/namespaces/${this.props.namespace}/${domain}/${this.props.object}?tab=traces&${URLParam.TRACING_TRACE_ID}=${traceId}&${URLParam.TRACING_SPAN_ID}=${spanId}`;
328	
329	      if (isParentKiosk(this.props.kiosk)) {
330	        kioskContextMenuAction(traceUrl);
331	      } else {
332	        router.navigate(traceUrl);
333	      }
334	    }
335	  };
336	
337	  private onDomainChange(dates: [Date, Date]): void {
338	    if (dates && dates[0] && dates[1]) {
339	      const range: TimeRange = {
340	        from: dates[0].getTime(),
341	        to: dates[1].getTime()
342	      };
343	
344	      this.props.setTimeRange(range);
345	    }
346	  }
347	
348	  render(): React.ReactNode {
349	    const urlParams = new URLSearchParams(location.getSearch());
350	    const expandedChart = urlParams.get('expand') ?? undefined;
351	
352	    // 20px (card margin) + 24px (card padding) + 51px (toolbar) + 15px (toolbar padding) + 24px (card padding) + 20px (card margin)
353	    const toolbarHeight = this.toolbarRef.current ? this.toolbarRef.current.clientHeight : 51;
354	    const toolbarSpace = 20 + 24 + toolbarHeight + 15 + 24 + 20;
355	    const dashboardHeight = this.state.tabHeight - toolbarSpace;
356	
357	    return (
358	      <>
359	        <RenderComponentScroll onResize={height => this.setState({ tabHeight: height })}>
360	          <Card className={fullHeightStyle}>
361	            <CardBody>
362	              {this.renderOptionsBar()}
363	
364	              {this.state.dashboard && (
365	                <Dashboard
366	                  dashboard={this.state.dashboard}
367	                  labelValues={MetricsHelper.convertAsPromLabels(this.state.labelsSettings)}
368	                  maximizedChart={expandedChart}
369	                  expandHandler={this.expandHandler}
370	                  onClick={this.onClickDataPoint}
371	                  labelPrettifier={MetricsHelper.prettyLabelValues}
372	                  overlay={this.state.spanOverlay}
373	                  showSpans={this.state.showSpans}
374	                  showTrendlines={this.state.showTrendlines}
375	                  dashboardHeight={dashboardHeight}
376	                  timeWindow={evalTimeRange(this.props.timeRange)}
377	                  brushHandlers={{ onDomainChangeEnd: (_, props) => this.onDomainChange(props.currentDomain.x) }}
378	                />
379	              )}
380	            </CardBody>
381	          </Card>
382	        </RenderComponentScroll>
383	
384	        <TimeDurationModal
385	          customDuration={true}
386	          isOpen={this.state.isTimeOptionsOpen}
387	          onConfirm={this.toggleTimeOptionsVisibility}
388	          onCancel={this.toggleTimeOptionsVisibility}
389	        />
390	      </>
391	    );
392	  }
393	
394	  private onTraceSpansChange = (checked: boolean, limit: number): void => {
395	    const urlParams = new URLSearchParams(location.getSearch());
396	    urlParams.set(URLParam.SHOW_SPANS, String(checked));
397	    if (checked) {
398	      urlParams.set(URLParam.TRACING_LIMIT_TRACES, String(limit));
399	    } else {
400	      urlParams.delete(URLParam.SHOW_SPANS);
401	    }
402	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
403	    this.setState({ showSpans: checked, traceLimit: limit });
404	  };
405	
406	  private onTrendlines = (checked: boolean): void => {
407	    const urlParams = new URLSearchParams(location.getSearch());
408	    urlParams.set(URLParam.SHOW_TRENDLINES, String(checked));
409	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
410	    this.setState({ showTrendlines: !this.state.showTrendlines });
411	  };
412	
413	  private toggleTimeOptionsVisibility = (): void => {
414	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
415	  };
416	
417	  private renderOptionsBar(): React.ReactNode {
418	    const hasHistogramsAverage =
419	      !this.state.crippledFeatures?.requestSizeAverage ||
420	      !this.state.crippledFeatures?.responseSizeAverage ||
421	      !this.state.crippledFeatures?.responseTimeAverage;
422	
423	    const hasHistogramsPercentiles =
424	      !this.state.crippledFeatures?.requestSizePercentiles ||
425	      !this.state.crippledFeatures?.responseSizePercentiles ||
426	      !this.state.crippledFeatures?.responseTimePercentiles;
427	
428	    return (
429	      <div ref={this.toolbarRef}>
430	        <Toolbar style={{ padding: 0, marginBottom: '1.25rem' }}>
431	          <ToolbarGroup>
432	            <ToolbarItem>
433	              <MetricsSettingsDropdown
434	                onChanged={this.onMetricsSettingsChanged}
435	                onLabelsFiltersChanged={this.onLabelsFiltersChanged}
436	                direction={this.props.direction}
437	                labelsSettings={this.state.labelsSettings}
438	                hasHistograms={true}
439	                hasHistogramsAverage={hasHistogramsAverage}
440	                hasHistogramsPercentiles={hasHistogramsPercentiles}
441	              />
442	            </ToolbarItem>
443	
444	            <ToolbarItem>
445	              <MetricsReporter
446	                onChanged={this.onReporterChanged}
447	                direction={this.props.direction}
448	                reporter={this.options.reporter}
449	              />
450	            </ToolbarItem>
451	
452	            {this.props.tracingIntegration && (
453	              <ToolbarItem style={{ alignSelf: 'center' }}>
454	                <TraceSpansLimit
455	                  label="Spans"
456	                  onChange={this.onTraceSpansChange}
457	                  showSpans={this.state.showSpans}
458	                  traceLimit={this.state.traceLimit}
459	                />
460	              </ToolbarItem>
461	            )}
462	
463	            <ToolbarItem style={{ alignSelf: 'center' }}>
464	              <Checkbox
465	                id="trendlines-show-"
466	                isChecked={this.state.showTrendlines}
467	                key="trendlines-show-chart"
468	                label="Trendlines"
469	                onChange={(_event, checked) => this.onTrendlines(checked)}
470	              />
471	            </ToolbarItem>
472	
473	            <ToolbarItem style={{ marginLeft: 'auto', paddingRight: '20px', display: 'block' }}>
474	              <GrafanaLinks
475	                links={this.state.grafanaInfo.externalLinks}
476	                namespace={this.props.namespace}
477	                object={this.props.object}
478	                objectType={this.props.objectType}
479	                datasourceUID={this.state.grafanaInfo.datasourceUID}
480	              />
481	              <PersesLinks
482	                links={this.state.persesInfo.externalLinks}
483	                namespace={this.props.namespace}
484	                object={this.props.object}
485	                objectType={this.props.objectType}
486	                project={this.state.persesInfo.project}
487	              />
488	            </ToolbarItem>
489	            <KioskElement>
490	              <ToolbarItem>
491	                <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} />
492	              </ToolbarItem>
493	            </KioskElement>
494	          </ToolbarGroup>
495	        </Toolbar>
496	      </div>
497	    );
498	  }
499	
500	  private expandHandler = (expandedChart?: string): void => {
501	    const urlParams = new URLSearchParams(location.getSearch());
502	    urlParams.delete('expand');
503	
504	    if (expandedChart) {
505	      urlParams.set('expand', expandedChart);
506	    }
507	
508	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
509	  };
510	}
511	
512	const mapStateToProps = (state: KialiAppState): ReduxStateProps => {
513	  return {
514	    externalServices: state.statusState.externalServices,
515	    kiosk: state.globalState.kiosk,
516	    tracingIntegration: state.tracingState.info ? state.tracingState.info.integration : false,
517	    timeRange: timeRangeSelector(state),
518	    refreshInterval: refreshIntervalSelector(state)
519	  };
520	};
521	
522	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
523	  return {
524	    setTimeRange: bindActionCreators(UserSettingsActions.setTimeRange, dispatch)
525	  };
526	};
527	
528	export const IstioMetrics = connect(mapStateToProps, mapDispatchToProps)(IstioMetricsComponent);

